	lib_name = #{lib_name}
	, lib_url            = #{lib_url}
	, lib_picture_url    = #{lib_picture_url}
	, lib_address        = #{lib_address}
	, lib_latitude       = #{lib_latitude}
	, lib_longitude      = #{lib_longitude}
	, lib_tel            = #{lib_tel}
	, lib_email          = #{lib_email}
	, lib_holiday_info   = #{lib_holiday_info}
	, lib_use_time       = #{lib_use_time}
	, lib_cabinet_yn     = #{lib_cabinet_yn}
	, lib_cabinet_url    = #{lib_cabinet_url}
	, lib_reg_cource_yn  = #{lib_reg_cource_yn}
	, lib_reg_cource_url = #{lib_reg_cource_url}
	, lib_webbooking_yn  = #{lib_webbooking_yn}
	, lib_webbooking_url = #{lib_webbooking_url}
