	, lib_etc_url        = #{lib_etc_url}
	, board_type  		 = #{board_type}
	, kiosk_type 		 = #{kiosk_type}
	, smartbook_type           = #{smartbook_type}
	, mediawall_type     = #{mediawall_type}
